/* Minimal Sortable — drag-and-drop reordering for lists and grids.
   Compatible with the SortableJS constructor API used in this app. */
(function (global) {
  'use strict';

  function closestMatch(el, selector) {
    while (el) {
      if (el.matches && el.matches(selector)) return el;
      el = el.parentElement;
    }
    return null;
  }

  function Sortable(el, options) {
    this.el = el;
    this.options = Object.assign({ handle: null, animation: 0 }, options || {});
    this._dragging = null;
    this._downOnHandle = false;
    this._init();
  }

  Sortable.prototype._init = function () {
    var self = this;
    this._markChildren();

    /* Track whether mousedown was on the handle */
    this.el.addEventListener('mousedown', function (e) {
      if (!self.options.handle) {
        self._downOnHandle = true;
        return;
      }
      self._downOnHandle = !!closestMatch(e.target, self.options.handle);
    });

    this.el.addEventListener('dragstart', function (e) {
      if (!self._downOnHandle) { e.preventDefault(); return; }
      var item = closestMatch(e.target, '[data-si]');
      if (!item) return;
      self._dragging = item;
      /* Defer opacity so the drag ghost captures the original look */
      requestAnimationFrame(function () {
        if (self._dragging) self._dragging.style.opacity = '0.4';
      });
      e.dataTransfer.effectAllowed = 'move';
    });

    this.el.addEventListener('dragend', function (e) {
      if (self._dragging) {
        self._dragging.style.opacity = '';
        var item = self._dragging;
        self._dragging = null;
        if (self.options.onEnd) self.options.onEnd.call(self, { item: item });
      }
    });

    this.el.addEventListener('dragover', function (e) {
      e.preventDefault();
      if (!self._dragging) return;
      var target = self._nearestItem(e.clientX, e.clientY);
      if (!target || target === self._dragging) return;
      var r = target.getBoundingClientRect();
      var vertDist = Math.abs(e.clientY - (r.top + r.height / 2));
      var insertAfter = vertDist < r.height / 2
        ? e.clientX > r.left + r.width / 2   /* same row: use horizontal position */
        : e.clientY > r.top + r.height / 2;  /* different row: use vertical position */
      self.el.insertBefore(self._dragging, insertAfter ? target.nextSibling : target);
    });
  };

  /* Find the visible item whose centre is closest to (x, y) */
  Sortable.prototype._nearestItem = function (x, y) {
    var best = null;
    var bestDist = Infinity;
    this.el.querySelectorAll('[data-si]').forEach(function (item) {
      if (item.style.opacity === '0.4') return;
      var r = item.getBoundingClientRect();
      var dx = x - (r.left + r.width / 2);
      var dy = y - (r.top + r.height / 2);
      var d = dx * dx + dy * dy;
      if (d < bestDist) { bestDist = d; best = item; }
    });
    return best;
  };

  Sortable.prototype._markChildren = function () {
    Array.prototype.forEach.call(this.el.children, function (child) {
      child.setAttribute('data-si', '');
      child.draggable = true;
    });
  };

  global.Sortable = Sortable;
}(typeof window !== 'undefined' ? window : this));
